import{_ as n,o as s,c as r,ak as l}from"./chunks/framework.DwHlt8HN.js";const g=JSON.parse('{"title":"简历常见问题与修改建议","description":"","frontmatter":{},"headers":[],"relativePath":"interview/resume/problem.md","filePath":"interview/resume/problem.md","lastUpdated":1774284433000}'),e={name:"interview/resume/problem.md"};function p(i,a,t,o,c,h){return s(),r("div",null,[...a[0]||(a[0]=[l(`<h1 id="简历常见问题与修改建议" tabindex="-1">简历常见问题与修改建议 <a class="header-anchor" href="#简历常见问题与修改建议" aria-label="Permalink to “简历常见问题与修改建议”">​</a></h1><blockquote><p>简历写完之后，最好找 3 个人帮你 review：你身边的同学、比你资深的人、有 HR 或猎头背景的人。</p></blockquote><h2 id="十大高频问题" tabindex="-1">十大高频问题 <a class="header-anchor" href="#十大高频问题" aria-label="Permalink to “十大高频问题”">​</a></h2><h3 id="问题一-简历太长或太短" tabindex="-1">问题一：简历太长或太短 <a class="header-anchor" href="#问题一-简历太长或太短" aria-label="Permalink to “问题一：简历太长或太短”">​</a></h3><p><strong>症状：</strong> 应届生写三页，或者工作三年只写半页。</p><p><strong>影响：</strong> 没人有耐心看完，或者让人觉得没什么可写的。</p><p><strong>建议：</strong></p><ul><li>应届生 / 0-3 年：1 页</li><li>3-5 年：1.5-2 页</li><li>5 年以上：2 页，核心放在最近两段经历上</li></ul><h3 id="问题二-技术栈堆砌-没有重点" tabindex="-1">问题二：技术栈堆砌，没有重点 <a class="header-anchor" href="#问题二-技术栈堆砌-没有重点" aria-label="Permalink to “问题二：技术栈堆砌，没有重点”">​</a></h3><p><strong>症状：</strong> 技术栈写了几十项，看不出主次。</p><p><strong>影响：</strong> 面试官无法快速判断你的核心竞争力。</p><p><strong>建议：</strong> 技术栈分类 + 按掌握程度分层，保留 10-15 项核心技能，删除不熟悉的。</p><h3 id="问题三-项目描述太笼统" tabindex="-1">问题三：项目描述太笼统 <a class="header-anchor" href="#问题三-项目描述太笼统" aria-label="Permalink to “问题三：项目描述太笼统”">​</a></h3><p><strong>症状：</strong> 「负责系统开发」「参与需求评审」这类描述太空。</p><p><strong>影响：</strong> 面试官没有提问的切入点。</p><p><strong>建议：</strong> 用 STAR 法则改写，加上具体数据和技术细节。</p><h3 id="问题四-项目经历没有亮点" tabindex="-1">问题四：项目经历没有亮点 <a class="header-anchor" href="#问题四-项目经历没有亮点" aria-label="Permalink to “问题四：项目经历没有亮点”">​</a></h3><p><strong>症状：</strong> 写的都是 CRUD，没有技术含量。</p><p><strong>影响：</strong> 面试官会认为你的能力止步于 CRUD。</p><p><strong>建议：</strong> 深挖每个项目的技术难点，可以从以下角度：</p><ul><li>性能优化：接口 RT 降低了多少</li><li>高并发：QPS 支撑多少</li><li>数据量：存储了多少数据</li><li>架构设计：用了什么设计模式/架构模式</li><li>问题解决：遇到过什么线上问题，怎么排查和解决的</li></ul><h3 id="问题五-数据夸大或造假" tabindex="-1">问题五：数据夸大或造假 <a class="header-anchor" href="#问题五-数据夸大或造假" aria-label="Permalink to “问题五：数据夸大或造假”">​</a></h3><p><strong>症状：</strong> 项目 QPS 虚高（「日均十亿级请求」），项目规模明显不匹配。</p><p><strong>影响：</strong> 面试追问立刻露馅，影响诚信。</p><p><strong>建议：</strong> 数据可以保守估计，但要真实。能讲清楚来龙去脉的数据才是好数据。</p><h3 id="问题六-个人信息遗漏关键项" tabindex="-1">问题六：个人信息遗漏关键项 <a class="header-anchor" href="#问题六-个人信息遗漏关键项" aria-label="Permalink to “问题六：个人信息遗漏关键项”">​</a></h3><p><strong>症状：</strong> 没写手机号、没写邮箱、文件名是「简历.pdf」。</p><p><strong>影响：</strong> HR 联系不到你。</p><p><strong>建议：</strong> 检查清单：</p><ul><li>[ ] 手机号（最好加分隔符如 138-xxxx-xxxx）</li><li>[ ] 邮箱（用专业邮箱，别用 QQ 邮箱昵称）</li><li>[ ] 简历文件名：<code>姓名-岗位-工作年限.pdf</code></li></ul><h3 id="问题七-自我评价太虚" tabindex="-1">问题七：自我评价太虚 <a class="header-anchor" href="#问题七-自我评价太虚" aria-label="Permalink to “问题七：自我评价太虚”">​</a></h3><p><strong>症状：</strong> 「热爱技术」「学习能力强」「善于沟通」—— 全是套话。</p><p><strong>影响：</strong> 等于没写，反而降低印象分。</p><p><strong>建议：</strong> 用事实说话，或者直接删掉自我评价。</p><h3 id="问题八-简历格式混乱" tabindex="-1">问题八：简历格式混乱 <a class="header-anchor" href="#问题八-简历格式混乱" aria-label="Permalink to “问题八：简历格式混乱”">​</a></h3><p><strong>症状：</strong> 字号不统一、日期不一致、缩进乱、标点乱。</p><p><strong>影响：</strong> 暴露态度问题。</p><p><strong>建议：</strong></p><ul><li>统一使用一种字体（推荐等线或 Arial）</li><li>统一日期格式（如 2023.06 - 2024.06）</li><li>用 Markdown 写，导出 PDF 格式最稳定</li><li>字号 10.5pt - 12pt，行距 1.2-1.5</li></ul><h3 id="问题九-项目经历全是「我」" tabindex="-1">问题九：项目经历全是「我」 <a class="header-anchor" href="#问题九-项目经历全是「我」" aria-label="Permalink to “问题九：项目经历全是「我」”">​</a></h3><p><strong>症状：</strong> 每个项目都写「我设计」「我实现」「我优化」。</p><p><strong>影响：</strong> 如果是团队项目，显得不真实，而且面试官会追问。</p><p><strong>建议：</strong> 明确区分个人贡献和团队协作。可以这样写：</p><blockquote><p>主导订单模块设计与实现（独立），日均处理 30 万订单... 参与用户中心模块开发（2 人协作），负责缓存层设计与实现...</p></blockquote><h3 id="问题十-简历不匹配岗位-jd" tabindex="-1">问题十：简历不匹配岗位 JD <a class="header-anchor" href="#问题十-简历不匹配岗位-jd" aria-label="Permalink to “问题十：简历不匹配岗位 JD”">​</a></h3><p><strong>症状：</strong> 用同一份简历投所有公司，不看 JD 要求。</p><p><strong>影响：</strong> 通过率极低。</p><p><strong>建议：</strong> 每投一家公司，根据 JD 调整简历的侧重点：</p><ul><li>JD 强调高并发 → 突出高并发项目</li><li>JD 强调中间件 → 突出中间件使用经验</li><li>JD 强调团队管理 → 突出带团队经验</li></ul><h2 id="修改清单" tabindex="-1">修改清单 <a class="header-anchor" href="#修改清单" aria-label="Permalink to “修改清单”">​</a></h2><p>完成初稿后，对照以下清单逐项检查：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>格式检查</span></span>
<span class="line"><span>□ 文件名为「姓名-岗位-年限.pdf」</span></span>
<span class="line"><span>□ 手机号和邮箱格式正确</span></span>
<span class="line"><span>□ 日期格式统一</span></span>
<span class="line"><span>□ 字号、字距一致</span></span>
<span class="line"><span>□ 没有错别字和乱码</span></span>
<span class="line"><span></span></span>
<span class="line"><span>内容检查</span></span>
<span class="line"><span>□ 技术栈数量控制在 10-15 项</span></span>
<span class="line"><span>□ 每个项目有量化数据</span></span>
<span class="line"><span>□ 每个项目有 1-2 个技术亮点</span></span>
<span class="line"><span>□ STAR 法则描述项目经历</span></span>
<span class="line"><span>□ 没有使用「精通」除非真的精通</span></span>
<span class="line"><span></span></span>
<span class="line"><span>针对性检查</span></span>
<span class="line"><span>□ 根据目标公司 JD 调整了侧重点</span></span>
<span class="line"><span>□ 删除了与岗位无关的内容</span></span>
<span class="line"><span>□ GitHub / 博客链接可正常访问（如有）</span></span>
<span class="line"><span>□ 没有敏感信息（身份证、详细住址等）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br></div></div><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to “总结”">​</a></h2><p>简历修改是一个不断迭代的过程：</p><ol><li><strong>写初稿</strong>：先按自己的想法写出来</li><li><strong>找反馈</strong>：让 2-3 个人帮你 review</li><li><strong>改问题</strong>：根据反馈修改</li><li><strong>再打磨</strong>：针对不同公司再做微调</li></ol><p>记住：<strong>简历不是写你做过什么，而是写你做成了什么</strong>。</p>`,56)])])}const d=n(e,[["render",p]]);export{g as __pageData,d as default};
